#include <pthread.h>

/* No static globals needed for test mode */
/* The test harness manages the test state */

validation.test_code:
static pthread_mutex_t test_lock = PTHREAD_MUTEX_INITIALIZER;
static int test_counter;

void *test_increment(void *arg) {
    (void)arg;
    pthread_mutex_lock(&test_lock);
    test_counter++;
    pthread_mutex_unlock(&test_lock);
    return NULL;
}

void test_mutex_lock_unlock_success(void) {
    test_lock = PTHREAD_MUTEX_INITIALIZER;
    test_counter = 0;
    int lock_rc = pthread_mutex_lock(&test_lock);
    TEST_ASSERT_EQUAL_INT(0, lock_rc);
    test_counter++;
    int unlock_rc = pthread_mutex_unlock(&test_lock);
    TEST_ASSERT_EQUAL_INT(0, unlock_rc);
}

void test_counter_increments_with_protection(void) {
    test_lock = PTHREAD_MUTEX_INITIALIZER;
    test_counter = 0;
    pthread_t t1, t2;
    pthread_create(&t1, NULL, test_increment, NULL);
    pthread_create(&t2, NULL, test_increment, NULL);
    pthread_join(t1, NULL);
    pthread_join(t2, NULL);
    TEST_ASSERT_EQUAL_INT(2, test_counter);
}

void test_mutex_protects_read(void) {
    test_lock = PTHREAD_MUTEX_INITIALIZER;
    test_counter = 5;
    pthread_mutex_lock(&test_lock);
    int val = test_counter;
    pthread_mutex_unlock(&test_lock);
    TEST_ASSERT_EQUAL_INT(5, val);
}

void test_multiple_lock_unlock(void) {
    test_lock = PTHREAD_MUTEX_INITIALIZER;
    test_counter = 0;
    for (int i = 0; i < 3; i++) {
        pthread_mutex_lock(&test_lock);
        test_counter++;
        pthread_mutex_unlock(&test_lock);
    }
    TEST_ASSERT_EQUAL_INT(3, test_counter);
}

int main(void) {
    RUN_TEST(test_mutex_lock_unlock_success);
    RUN_TEST(test_counter_increments_with_protection);
    RUN_TEST(test_mutex_protects_read);
    RUN_TEST(test_multiple_lock_unlock);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

